actions.script:
try {
    def debitConfig = ec.entity.find("trade.common.TradeConfig").condition("configKey", "GL_TRADE_DEBIT").one()
    def creditConfig = ec.entity.find("trade.common.TradeConfig").condition("configKey", "GL_TRADE_CREDIT").one()
    def debitGl = debitConfig?.configValue ?: '111000'
    def creditGl = creditConfig?.configValue ?: '411000'

    def acctgTransId = ec.entity.makeValue("mantle.ledger.transaction.AcctgTrans", [
        acctgTransTypeEnumId: 'ATT_FINANCIAL_ENTRY',
        lastUpdatedStamp: ec.user.nowTimestamp,
        isSettled: 'Y'
    ]).setSequencedIdPrimary().create().acctgTransId

    ec.entity.makeValue("mantle.ledger.transaction.AcctgTransEntry", [acctgTransId: acctgTransId, acctgTransEntrySeqId: '01', glAccountId: debitGl, amount: amount, debitCreditFlag: 'D']).create()
    ec.entity.makeValue("mantle.ledger.transaction.AcctgTransEntry", [acctgTransId: acctgTransId, acctgTransEntrySeqId: '02', glAccountId: creditGl, amount: amount, debitCreditFlag: 'C']).create()
} catch (Exception e) { ec.logger.error("Accounting error: " + e.message) }

def feeConfig = feeConfigs ? feeConfigs[0] : null
BigDecimal result = 0.0
if (feeConfig == null) {
    result = baseAmount * 0.0025
    if (minCharge && result < minCharge) result = minCharge
    if (maxCharge && result > maxCharge) result = maxCharge
} else {
    def base = feeConfig.baseValue ?: feeConfig.ratePercent ?: 0.0
    if (feeConfig.calculationTypeEnumId == 'PERCENTAGE') {
        result = baseAmount * base
    } else {
        result = base
    }
    def minFloor = minCharge ?: feeConfig.minFloorAmount
    def maxCeiling = maxCharge ?: feeConfig.maxCeilingAmount
    if (minFloor && result < minFloor) result = minFloor
    if (maxCeiling && result > maxCeiling) result = maxCeiling
}
context.totalFee = result
